     5→//! VVK Parcel Release Utilities
     6→//!
     7→//! Provides asset collection and branding for VVK parcel creation.
     8→//!
     9→//! - `vofr_collect`: Enumerate kit files, copy to staging (excludes vov_veiled/)
    10→//! - `vofr_brand`: Compute super-SHA, allocate hallmark, write brand file
    11→
    12→use std::collections::BTreeMap;
    13→use std::fs;
    14→use std::path::{Path, PathBuf};
    15→
    16→use crate::vofc_registry::{DISTRIBUTABLE_KITS, vofc_Kit};
    17→
    18→// =============================================================================
    19→// Constants
    20→// =============================================================================
    21→
    22→/// Starting hallmark for new registries
    23→const VOFR_HALLMARK_START: u32 = 1000;
    24→
    25→/// Brand file JSON field tags (match VOS spec entity members)
    26→const VOFR_BRAND_HALLMARK: &str = "vvbh_hallmark";
    27→const VOFR_BRAND_DATE: &str = "vvbd_date";
    28→const VOFR_BRAND_SHA: &str = "vvbs_sha";
    29→const VOFR_BRAND_COMMIT: &str = "vvbc_commit";
    30→const VOFR_BRAND_KITS: &str = "vvbk_kits";
    31→
    32→/// Registry JSON field
    33→const VOFR_REGISTRY_HALLMARKS: &str = "hallmarks";
    34→
    35→// =============================================================================
    36→// Public Types
    37→// =============================================================================
    38→
    39→/// Result of asset collection.
    40→#[derive(Debug)]
    41→pub struct vofr_CollectResult {
    42→    /// Number of files copied per kit
    43→    pub kit_counts: BTreeMap<String, u32>,
    44→    /// Total files copied
    45→    pub total_files: u32,
    46→    /// Commands routed to commands/ directory
    47→    pub commands_routed: u32,
    48→}
    49→
    50→/// Result of branding operation.
    51→#[derive(Debug)]
    52→pub struct vofr_BrandResult {
    53→    /// Allocated hallmark
    54→    pub hallmark: u32,
    55→    /// Whether this was a new hallmark (vs reused)
    56→    pub is_new: bool,
    57→    /// Computed super-SHA
    58→    pub super_sha: String,
    59→}
    60→
    61→/// Registry entry for a hallmark.
    62→#[derive(Debug, Clone)]
    63→pub struct vofr_RegistryEntry {
    64→    pub date: String,
    65→    pub sha: String,
    66→}
    67→
    68→// =============================================================================
    69→// Public Functions
    70→// =============================================================================
    71→
    72→/// Collect kit assets to staging directory.
    73→///
    74→/// # Arguments
    75→/// * `tools_dir` - Source Tools/ directory
    76→/// * `staging_dir` - Target staging directory
    77→/// * `install_script_path` - Path to vvi_install.sh to copy to staging root
    78→/// * `managed_kits` - List of kit IDs to include (from BURC_MANAGED_KITS)
    79→///
    80→/// # Returns
    81→/// CollectResult with file counts, or error message
    82→pub fn vofr_collect(
    83→    tools_dir: &Path,
    84→    staging_dir: &Path,
    85→    install_script_path: &Path,
    86→    managed_kits: &[String],
    87→) -> Result<vofr_CollectResult, String> {
    88→    let mut kit_counts = BTreeMap::new();
    89→    let mut total_files = 0u32;
    90→    let mut commands_routed = 0u32;
    91→
    92→    // Create staging directories
    93→    let kits_dir = staging_dir.join("kits");
    94→    fs::create_dir_all(&kits_dir)
    95→        .map_err(|e| format!("Failed to create kits dir: {}", e))?;
    96→
    97→    // Process only kits in managed_kits list
    98→    for kit_id in managed_kits {
    99→        let kit = DISTRIBUTABLE_KITS
   100→            .iter()
   101→            .find(|k| k.cipher.kit_id() == *kit_id)
   102→            .ok_or_else(|| format!("Kit '{}' not found in registry", kit_id))?;
   103→
   104→        let kit_source = tools_dir.join(kit_id);
   105→        let kit_staging = kits_dir.join(kit_id);
   106→
   107→        if !kit_source.exists() {
   108→            return Err(format!("Kit source not found: {}", kit_source.display()));
   109→        }
   110→
   111→        let (count, cmd_count) = zvofr_collect_kit(&kit_source, &kit_staging, kit)?;
   112→        kit_counts.insert(kit_id.clone(), count);
   113→        total_files += count;
   114→        commands_routed += cmd_count;
   115→
   116→        // Copy managed section templates from vov_veiled/ to templates/
   117→        let template_count = zvofr_copy_templates(&kit_source, &kit_staging, kit)?;
   118→        total_files += template_count;
   119→    }
   120→
   121→    // Copy install script to staging root
   122→    let install_dest = staging_dir.join("vvi_install.sh");
   123→    fs::copy(install_script_path, &install_dest)
   124→        .map_err(|e| format!("Failed to copy install script: {}", e))?;
   125→    total_files += 1;
   126→
   127→    Ok(vofr_CollectResult {
   128→        kit_counts,
   129→        total_files,
   130→        commands_routed,
   131→    })
   132→}
   133→
   134→/// Brand a staging directory with hallmark and metadata.
   135→///
   136→/// # Arguments
   137→/// * `staging_dir` - Staging directory with collected assets
   138→/// * `registry_path` - Path to vovr_registry.json
   139→/// * `commit_sha` - Current git commit SHA
   140→/// * `managed_kits` - List of kit IDs included (from BURC_MANAGED_KITS)
   141→///
   142→/// # Returns
   143→/// BrandResult with hallmark info, or error message
   144→pub fn vofr_brand(
   145→    staging_dir: &Path,
   146→    registry_path: &Path,
   147→    commit_sha: &str,
   148→    managed_kits: &[String],
   149→) -> Result<vofr_BrandResult, String> {
   150→    // Compute super-SHA of staging content
   151→    let super_sha = zvofr_compute_super_sha(staging_dir)?;
   152→
   153→    // Load or create registry
   154→    let mut registry = zvofr_load_registry(registry_path)?;
   155→
   156→    // Check if SHA already exists
   157→    let (hallmark, is_new) = if let Some(existing) = zvofr_find_by_sha(&registry, &super_sha) {
   158→        (existing, false)
   159→    } else {
   160→        let new_hallmark = zvofr_allocate_hallmark(&registry);
   161→        (new_hallmark, true)
   162→    };
   163→
   164→    // Generate timestamp
   165→    let date = zvofr_generate_date();
   166→
   167→    // If new, update registry
   168→    if is_new {
   169→        registry.insert(hallmark, vofr_RegistryEntry {
   170→            date: date.clone(),
   171→            sha: super_sha.clone(),
   172→        });
   173→        zvofr_save_registry(registry_path, &registry)?;
   174→    }
   175→
   176→    // Write brand file with managed_kits as the kit list
   177→    let brand_path = staging_dir.join("vvbf_brand.json");
   178→    zvofr_write_brand_file(&brand_path, hallmark, &date, &super_sha, commit_sha, managed_kits)?;
   179→
   180→    Ok(vofr_BrandResult {
   181→        hallmark,
   182→        is_new,
   183→        super_sha,
   184→    })
   185→}
   186→
   187→/// Load registry from JSON file.
   188→pub fn vofr_load_registry(path: &Path) -> Result<BTreeMap<u32, vofr_RegistryEntry>, String> {
   189→    zvofr_load_registry(path)
   190→}
   191→
   192→// =============================================================================
   193→// Internal Functions (zvofr_*)
   194→// =============================================================================
   195→
   196→/// Copy managed section templates from vov_veiled/ to templates/.
   197→fn zvofr_copy_templates(
   198→    kit_source: &Path,
   199→    kit_staging: &Path,
   200→    kit: &vofc_Kit,
   201→) -> Result<u32, String> {
   202→    let mut count = 0u32;
   203→
   204→    if kit.managed_sections.is_empty() {
   205→        return Ok(0);
   206→    }
   207→
   208→    let veiled_dir = kit_source.join("vov_veiled");
   209→    let templates_dir = kit_staging.join("templates");
   210→
   211→    for section in kit.managed_sections {
   212→        let template_source = veiled_dir.join(section.template_path);
   213→        if !template_source.exists() {
   214→            return Err(format!(
   215→                "Template not found for kit {}: {}",
   216→                kit.cipher.kit_id(),
   217→                template_source.display()
   218→            ));
   219→        }
   220→
   221→        fs::create_dir_all(&templates_dir)
   222→            .map_err(|e| format!("Failed to create templates dir: {}", e))?;
   223→
   224→        let template_dest = templates_dir.join(section.template_path);
   225→        fs::copy(&template_source, &template_dest)
   226→            .map_err(|e| format!("Failed to copy template {}: {}", section.template_path, e))?;
   227→
   228→        count += 1;
   229→    }
   230→
   231→    Ok(count)
   232→}
   233→
   234→/// Collect a single kit's assets.
   235→fn zvofr_collect_kit(
   236→    source: &Path,
   237→    staging: &Path,
   238→    kit: &vofc_Kit,
   239→) -> Result<(u32, u32), String> {
   240→    let mut count = 0u32;
   241→    let mut cmd_count = 0u32;
   242→    let cipher = kit.cipher.prefix();
   243→
   244→    // Walk source directory
   245→    let entries = zvofr_walk_dir(source)?;
   246→
   247→    for entry in entries {
   248→        let rel_path = entry.strip_prefix(source)
   249→            .map_err(|e| format!("Path strip failed: {}", e))?;
   250→
   251→        // Skip vov_veiled/ directory
   252→        if zvofr_is_veiled_path(rel_path) {
   253→            continue;
   254→        }
   255→
   256→        // Determine destination
   257→        let file_name = rel_path.file_name()
   258→            .and_then(|n| n.to_str())
   259→            .unwrap_or("");
   260→
   261→        let dest = if zvofr_is_command_file(file_name, cipher) {
   262→            // Route commands to commands/ subdirectory
   263→            cmd_count += 1;
   264→            let commands_dir = staging.join("commands");
   265→            fs::create_dir_all(&commands_dir)
   266→                .map_err(|e| format!("Failed to create commands dir: {}", e))?;
   267→            commands_dir.join(file_name)
   268→        } else {
   269→            // Default: preserve relative path
   270→            staging.join(rel_path)
   271→        };
   272→
   273→        // Create parent directories
   274→        if let Some(parent) = dest.parent() {
   275→            fs::create_dir_all(parent)
   276→                .map_err(|e| format!("Failed to create dir {}: {}", parent.display(), e))?;
   277→        }
   278→
   279→        // Copy file
   280→        fs::copy(&entry, &dest)
   281→            .map_err(|e| format!("Failed to copy {} to {}: {}", entry.display(), dest.display(), e))?;
   282→
   283→        count += 1;
   284→    }
   285→
   286→    Ok((count, cmd_count))
   287→}
   288→
   289→/// Walk directory recursively, returning all file paths.
   290→fn zvofr_walk_dir(dir: &Path) -> Result<Vec<PathBuf>, String> {
   291→    let mut files = Vec::new();
   292→
   293→    if !dir.is_dir() {
   294→        return Ok(files);
   295→    }
   296→
   297→    let entries = fs::read_dir(dir)
   298→        .map_err(|e| format!("Failed to read dir {}: {}", dir.display(), e))?;
   299→
   300→    for entry in entries {
   301→        let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
   302→        let path = entry.path();
   303→
   304→        if path.is_dir() {
   305→            files.extend(zvofr_walk_dir(&path)?);
   306→        } else {
   307→            files.push(path);
   308→        }
   309→    }
   310→
   311→    Ok(files)
   312→}
   313→
   314→/// Check if path is within vov_veiled/ directory.
   315→fn zvofr_is_veiled_path(rel_path: &Path) -> bool {
   316→    for component in rel_path.components() {
   317→        if let std::path::Component::Normal(name) = component {
   318→            if name == "vov_veiled" {
   319→                return true;
   320→            }
   321→        }
   322→    }
   323→    false
   324→}
   325→
   326→/// Check if file is a command file (matches {cipher}c-*.md pattern).
   327→fn zvofr_is_command_file(file_name: &str, cipher: &str) -> bool {
   328→    // Pattern: {cipher}c-*.md
   329→    let prefix = format!("{}c-", cipher);
   330→    file_name.starts_with(&prefix) && file_name.ends_with(".md")
   331→}
   332→
   333→/// Compute order-independent super-SHA of staging directory.
   334→fn zvofr_compute_super_sha(staging_dir: &Path) -> Result<String, String> {
   335→    use std::collections::BTreeSet;
   336→
   337→    let mut file_hashes: BTreeSet<String> = BTreeSet::new();
   338→
   339→    let files = zvofr_walk_dir(staging_dir)?;
   340→
   341→    for file_path in files {
   342→        let rel_path = file_path.strip_prefix(staging_dir)
   343→            .map_err(|e| format!("Strip prefix failed: {}", e))?;
   344→
   345→        // Skip brand file itself
   346→        if rel_path == Path::new("vvbf_brand.json") {
   347→            continue;
   348→        }
   349→
   350→        // Hash: path + content
   351→        let path_str = rel_path.to_string_lossy();
   352→        let content = fs::read(&file_path)
   353→            .map_err(|e| format!("Failed to read {}: {}", file_path.display(), e))?;
   354→
   355→        let hash = zvofr_sha256_bytes(format!("{}:{}", path_str, zvofr_sha256_bytes(&content)).as_bytes());
   356→        file_hashes.insert(hash);
   357→    }
   358→
   359→    // Combine all hashes
   360→    let combined = file_hashes.into_iter().collect::<Vec<_>>().join("\n");
   361→    Ok(zvofr_sha256_bytes(combined.as_bytes()))
   362→}
   363→
   364→/// Compute SHA256 of bytes, return hex string.
   365→fn zvofr_sha256_bytes(data: &[u8]) -> String {
   366→    // Simple SHA256 implementation using standard library
   367→    // In production, would use sha2 crate, but avoiding extra dependencies
   368→    use std::process::{Command, Stdio};
   369→    use std::io::Write;
   370→
   371→    let mut child = Command::new("shasum")
   372→        .args(["-a", "256"])
   373→        .stdin(Stdio::piped())
   374→        .stdout(Stdio::piped())
   375→        .spawn()
   376→        .expect("Failed to spawn shasum");
   377→
   378→    {
   379→        let stdin = child.stdin.as_mut().expect("Failed to open stdin");
   380→        stdin.write_all(data).expect("Failed to write to stdin");
   381→    }
   382→
   383→    let output = child.wait_with_output().expect("Failed to read shasum output");
   384→    let stdout = String::from_utf8_lossy(&output.stdout);
   385→    stdout.split_whitespace().next().unwrap_or("").to_string()
   386→}
   387→
   388→/// Load registry from JSON file.
   389→fn zvofr_load_registry(path: &Path) -> Result<BTreeMap<u32, vofr_RegistryEntry>, String> {
   390→    if !path.exists() {
   391→        return Ok(BTreeMap::new());
   392→    }
   393→
   394→    let content = fs::read_to_string(path)
   395→        .map_err(|e| format!("Failed to read registry: {}", e))?;
   396→
   397→    let json: serde_json::Value = serde_json::from_str(&content)
   398→        .map_err(|e| format!("Failed to parse registry JSON: {}", e))?;
   399→
   400→    let hallmarks = json.get(VOFR_REGISTRY_HALLMARKS)
   401→        .and_then(|v| v.as_object())
   402→        .ok_or_else(|| "Registry missing 'hallmarks' object".to_string())?;
   403→
   404→    let mut registry = BTreeMap::new();
   405→
   406→    for (key, value) in hallmarks {
   407→        let hallmark: u32 = key.parse()
   408→            .map_err(|e| format!("Invalid hallmark key '{}': {}", key, e))?;
   409→
   410→        let date = value.get("date")
   411→            .and_then(|v| v.as_str())
   412→            .ok_or_else(|| format!("Hallmark {} missing 'date'", hallmark))?
   413→            .to_string();
   414→
   415→        let sha = value.get("sha")
   416→            .and_then(|v| v.as_str())
   417→            .ok_or_else(|| format!("Hallmark {} missing 'sha'", hallmark))?
   418→            .to_string();
   419→
   420→        registry.insert(hallmark, vofr_RegistryEntry { date, sha });
   421→    }
   422→
   423→    Ok(registry)
   424→}
   425→
   426→/// Save registry to JSON file.
   427→fn zvofr_save_registry(path: &Path, registry: &BTreeMap<u32, vofr_RegistryEntry>) -> Result<(), String> {
   428→    let mut hallmarks = serde_json::Map::new();
   429→
   430→    for (hallmark, entry) in registry {
   431→        let mut entry_obj = serde_json::Map::new();
   432→        entry_obj.insert("date".to_string(), serde_json::Value::String(entry.date.clone()));
   433→        entry_obj.insert("sha".to_string(), serde_json::Value::String(entry.sha.clone()));
   434→        hallmarks.insert(hallmark.to_string(), serde_json::Value::Object(entry_obj));
   435→    }
   436→
   437→    let mut root = serde_json::Map::new();
   438→    root.insert(VOFR_REGISTRY_HALLMARKS.to_string(), serde_json::Value::Object(hallmarks));
   439→
   440→    let json = serde_json::to_string_pretty(&serde_json::Value::Object(root))
   441→        .map_err(|e| format!("Failed to serialize registry: {}", e))?;
   442→
   443→    fs::write(path, json)
   444→        .map_err(|e| format!("Failed to write registry: {}", e))?;
   445→
   446→    Ok(())
   447→}
   448→
   449→/// Find hallmark by SHA.
   450→fn zvofr_find_by_sha(registry: &BTreeMap<u32, vofr_RegistryEntry>, sha: &str) -> Option<u32> {
   451→    for (hallmark, entry) in registry {
   452→        if entry.sha == sha {
   453→            return Some(*hallmark);
   454→        }
   455→    }
   456→    None
   457→}
   458→
   459→/// Allocate next sequential hallmark.
   460→fn zvofr_allocate_hallmark(registry: &BTreeMap<u32, vofr_RegistryEntry>) -> u32 {
   461→    registry.keys().max().map(|m| m + 1).unwrap_or(VOFR_HALLMARK_START)
   462→}
   463→
   464→/// Generate date string in YYMMDD-HHMM format.
   465→fn zvofr_generate_date() -> String {
   466→    use std::process::Command;
   467→
   468→    let output = Command::new("date")
   469→        .args(["+%y%m%d-%H%M"])
   470→        .output()
   471→        .expect("Failed to run date command");
   472→
   473→    String::from_utf8_lossy(&output.stdout).trim().to_string()
   474→}
   475→
   476→/// Write brand file to staging.
   477→fn zvofr_write_brand_file(
   478→    path: &Path,
   479→    hallmark: u32,
   480→    date: &str,
   481→    sha: &str,
   482→    commit: &str,
   483→    kits: &[String],
   484→) -> Result<(), String> {
   485→    let mut root = serde_json::Map::new();
   486→
   487→    root.insert(VOFR_BRAND_HALLMARK.to_string(), serde_json::Value::Number(hallmark.into()));
   488→    root.insert(VOFR_BRAND_DATE.to_string(), serde_json::Value::String(date.to_string()));
   489→    root.insert(VOFR_BRAND_SHA.to_string(), serde_json::Value::String(sha.to_string()));
   490→    root.insert(VOFR_BRAND_COMMIT.to_string(), serde_json::Value::String(commit.to_string()));
   491→
   492→    let kit_values: Vec<serde_json::Value> = kits
   493→        .iter()
   494→        .map(|k| serde_json::Value::String(k.clone()))
   495→        .collect();
   496→    root.insert(VOFR_BRAND_KITS.to_string(), serde_json::Value::Array(kit_values));
   497→
   498→    let json = serde_json::to_string_pretty(&serde_json::Value::Object(root))
   499→        .map_err(|e| format!("Failed to serialize brand file: {}", e))?;
   500→
   501→    fs::write(path, json)
   502→        .map_err(|e| format!("Failed to write brand file: {}", e))?;
   503→
   504→    Ok(())
   505→}
   506→
   507→#[cfg(test)]
   508→mod tests {
   509→    use super::*;
   510→    use std::fs;
   511→
   512→    #[test]
   513→    fn vofr_is_command_file_test() {
   514→        assert!(zvofr_is_command_file("jjc-heat-mount.md", "jj"));
   515→        assert!(zvofr_is_command_file("vvc-commit.md", "vv"));
   516→        assert!(!zvofr_is_command_file("jju_utility.sh", "jj"));
   517→        assert!(!zvofr_is_command_file("README.md", "jj"));
   518→        assert!(!zvofr_is_command_file("jjc-heat-mount.txt", "jj"));
   519→    }
   520→
   521→    #[test]
   522→    fn vofr_is_veiled_path_test() {
   523→        assert!(zvofr_is_veiled_path(Path::new("vov_veiled/test.rs")));
   524→        assert!(zvofr_is_veiled_path(Path::new("foo/vov_veiled/bar.rs")));
   525→        assert!(!zvofr_is_veiled_path(Path::new("commands/jjc-test.md")));
   526→        assert!(!zvofr_is_veiled_path(Path::new("buc_command.sh")));
   527→    }
   528→
   529→    #[test]
   530→    fn vofr_hallmark_allocation_test() {
   531→        let empty: BTreeMap<u32, vofr_RegistryEntry> = BTreeMap::new();
   532→        assert_eq!(zvofr_allocate_hallmark(&empty), VOFR_HALLMARK_START);
   533→
   534→        let mut registry = BTreeMap::new();
   535→        registry.insert(1000, vofr_RegistryEntry {
   536→            date: "260117-1400".to_string(),
