     5→//! VVK Emplace/Vacate - Install and uninstall kit assets
     6→//!
     7→//! Full install/uninstall operations including git commits.
     8→//! Bash scripts (vvi_install.sh, vvu_uninstall.sh) are thin bootstraps
     9→//! that detect platform and exec the binary.
    10→//!
    11→//! Emplace behavior (nuclear install):
    12→//! 1. Parse burc.env, resolve paths relative to burc.env location
    13→//! 2. Verify git repo is clean
    14→//! 3. Read brand identity from parcel
    15→//! 4. Validate exact match: parcel kits == BURC_MANAGED_KITS
    16→//! 5. Delete .vvk/ and kit directories (nuclear cleanup)
    17→//! 6. Create .vvk/, copy brand file
    18→//! 7. Copy kit directories, route commands/hooks
    19→//! 8. Freshen CLAUDE.md with kit sections
    20→//! 9. Commit installation
    21→//!
    22→//! Vacate behavior (removes Claude integration, preserves kit scripts):
    23→//! 1. Parse burc.env, verify git clean
    24→//! 2. Read brand file from .vvk/ to get kit list
    25→//! 3. Remove commands and hooks from .claude/
    26→//! 4. Collapse CLAUDE.md sections to UNINSTALLED markers
    27→//! 5. Delete vvx binary from Tools/vvk/bin/
    28→//! 6. Delete brand file and .vvk/
    29→//! 7. Commit uninstallation
    30→//!
    31→//! Note: Kit directories (buk/, jjk/, etc.) are intentionally preserved.
    32→//! They contain open-source utilities usable outside Claude Code.
    33→
    34→use std::collections::HashMap;
    35→use std::fs;
    36→use std::path::{Path, PathBuf};
    37→use std::process::Command;
    38→
    39→use crate::voff_freshen::{voff_freshen, voff_collapse, voff_ManagedSection};
    40→use crate::vofc_registry::vofc_find_kit_by_id;
    41→
    42→// =============================================================================
    43→// Constants
    44→// =============================================================================
    45→
    46→/// Brand file JSON field tags (must match vofr_release.rs)
    47→const VOFE_BRAND_HALLMARK: &str = "vvbh_hallmark";
    48→const VOFE_BRAND_KITS: &str = "vvbk_kits";
    49→
    50→// =============================================================================
    51→// Git Operations
    52→// =============================================================================
    53→
    54→/// Check that git working tree is clean (no uncommitted changes).
    55→fn zvofe_check_git_clean(project_root: &Path) -> Result<(), String> {
    56→    let output = Command::new("git")
    57→        .args(["status", "--porcelain"])
    58→        .current_dir(project_root)
    59→        .output()
    60→        .map_err(|e| format!("Failed to run git status: {}", e))?;
    61→
    62→    if !output.status.success() {
    63→        let stderr = String::from_utf8_lossy(&output.stderr);
    64→        return Err(format!("git status failed: {}", stderr.trim()));
    65→    }
    66→
    67→    if !output.stdout.is_empty() {
    68→        return Err(
    69→            "Target repo has uncommitted changes. Commit or stash before install.".to_string(),
    70→        );
    71→    }
    72→
    73→    Ok(())
    74→}
    75→
    76→/// Check that path is a git repository.
    77→fn zvofe_check_is_git_repo(project_root: &Path) -> Result<(), String> {
    78→    let output = Command::new("git")
    79→        .args(["rev-parse", "--git-dir"])
    80→        .current_dir(project_root)
    81→        .output()
    82→        .map_err(|e| format!("Failed to run git rev-parse: {}", e))?;
    83→
    84→    if !output.status.success() {
    85→        return Err(format!(
    86→            "Target is not a git repository: {}",
    87→            project_root.display()
    88→        ));
    89→    }
    90→
    91→    Ok(())
    92→}
    93→
    94→/// Run git add -A and commit with message.
    95→fn zvofe_git_commit(project_root: &Path, message: &str) -> Result<(), String> {
    96→    // Stage all changes
    97→    let output = Command::new("git")
    98→        .args(["add", "-A"])
    99→        .current_dir(project_root)
   100→        .output()
   101→        .map_err(|e| format!("Failed to run git add: {}", e))?;
   102→
   103→    if !output.status.success() {
   104→        let stderr = String::from_utf8_lossy(&output.stderr);
   105→        return Err(format!("git add failed: {}", stderr.trim()));
   106→    }
   107→
   108→    // Commit
   109→    let output = Command::new("git")
   110→        .args(["commit", "-m", message])
   111→        .current_dir(project_root)
   112→        .output()
   113→        .map_err(|e| format!("Failed to run git commit: {}", e))?;
   114→
   115→    if !output.status.success() {
   116→        let stderr = String::from_utf8_lossy(&output.stderr);
   117→        // "nothing to commit" is not an error for us
   118→        if stderr.contains("nothing to commit") {
   119→            return Ok(());
   120→        }
   121→        return Err(format!("git commit failed: {}", stderr.trim()));
   122→    }
   123→
   124→    Ok(())
   125→}
   126→
   127→// =============================================================================
   128→// Public Types
   129→// =============================================================================
   130→
   131→/// Arguments for emplace operation.
   132→#[derive(Debug)]
   133→pub struct vofe_EmplaceArgs {
   134→    /// Path to extracted parcel directory
