   304→/// Remove kit assets from target repo.
   305→///
   306→/// # Arguments
   307→/// * `args` - Vacate arguments (burc.env path)
   308→///
   309→/// # Returns
   310→/// VacateResult with removal summary, or error message
   311→pub fn vofe_vacate(args: &vofe_VacateArgs) -> Result<vofe_VacateResult, String> {
   312→    eprintln!("vacate: removing kit assets...");
   313→    eprintln!("  burc: {}", args.burc_path.display());
   314→
   315→    // 1. Parse BURC
   316→    let burc = zvofe_parse_burc(&args.burc_path)?;
   317→
   318→    // 2. Validate git state
   319→    zvofe_check_git_clean(&burc.project_root)?;
   320→
   321→    // 3. Read brand file from .vvk/
   322→    let brand_path = burc.project_root.join(".vvk").join("vvbf_brand.json");
   323→    if !brand_path.exists() {
   324→        return Err("No VVK installation found (.vvk/vvbf_brand.json missing)".to_string());
   325→    }
   326→    let (_hallmark, kit_ids) = zvofe_read_brand(&brand_path)?;
   327→
   328→    // 4. Remove commands and hooks
   329→    let mut total_files = 0u32;
   330→    let mut commands_removed = 0u32;
   331→    let mut hooks_removed = 0u32;
   332→
   333→    let commands_dir = burc.project_root.join(".claude").join("commands");
   334→    let hooks_dir = burc.project_root.join(".claude").join("hooks");
   335→
   336→    for kit_id in &kit_ids {
   337→        // Get cipher from kit_id (e.g., "jjk" -> "jj")
   338→        let cipher = &kit_id[..kit_id.len().saturating_sub(1)];
   339→
   340→        // Remove commands matching {cipher}c-*.md
   341→        if commands_dir.exists() {
   342→            commands_removed += zvofe_remove_matching_files(&commands_dir, cipher, true)?;
   343→        }
   344→
   345→        // Remove hooks matching {cipher}h_*
   346→        if hooks_dir.exists() {
   347→            hooks_removed += zvofe_remove_matching_files(&hooks_dir, cipher, false)?;
   348→        }
   349→    }
   350→
   351→    // 5. Collapse CLAUDE.md sections (get tags from registry)
   352→    let section_tags: Vec<String> = kit_ids
   353→        .iter()
   354→        .filter_map(|kit_id| vofc_find_kit_by_id(kit_id))
   355→        .flat_map(|kit| kit.managed_sections.iter().map(|s| s.tag.to_string()))
   356→        .collect();
   357→
   358→    let claude_path = burc.project_root.join("CLAUDE.md");
   359→    zvofe_collapse_claude(&claude_path, &section_tags)?;
   360→
   361→    // 6. Delete vvx binary from Tools/vvk/bin/
   362→    // Kit directories are intentionally preserved (open-source utilities)
   363→    let vvk_bin_dir = burc.tools_dir.join("vvk").join("bin");
   364→    if vvk_bin_dir.exists() {
   365→        let entries = fs::read_dir(&vvk_bin_dir)
   366→            .map_err(|e| format!("Failed to read vvk bin dir: {}", e))?;
   367→
   368→        for entry in entries {
   369→            let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
   370→            let path = entry.path();
   371→            let file_name = path.file_name().and_then(|n| n.to_str()).unwrap_or("");
   372→
   373→            // Remove vvx binaries (vvx-darwin-arm64, vvx-linux-x86_64, etc.)
   374→            if file_name.starts_with("vvx") {
   375→                fs::remove_file(&path)
   376→                    .map_err(|e| format!("Failed to remove vvx binary {}: {}", path.display(), e))?;
   377→                total_files += 1;
   378→                eprintln!("  removed: {}", path.display());
   379→            }
   380→        }
   381→    }
   382→
   383→    // 7. Delete brand file and .vvk/
   384→    fs::remove_file(&brand_path)
   385→        .map_err(|e| format!("Failed to remove brand file: {}", e))?;
   386→
   387→    let vvk_dir = burc.project_root.join(".vvk");
   388→    if vvk_dir.exists() {
   389→        // Remove .vvk/ directory
   390→        let _ = fs::remove_dir(&vvk_dir);
   391→    }
   392→
   393→    // 8. Commit uninstallation
   394→    zvofe_git_commit(&burc.project_root, "VVK uninstall")?;
   395→
   396→    eprintln!("vacate: success - {} files, {} commands, {} hooks removed", total_files, commands_removed, hooks_removed);
   397→
   398→    Ok(vofe_VacateResult {
   399→        kits_removed: kit_ids,
   400→        files_deleted: total_files,
   401→        commands_removed,
   402→        hooks_removed,
   403→        claude_sections_collapsed: section_tags,
   404→    })
   405→}
