   410→
   411→/// Parse burc.env file to extract environment variables.
   412→/// BURC_PROJECT_ROOT is the path from burc.env's location to the project root.
   413→/// BURC_TOOLS_DIR is resolved relative to the resolved project_root (per BURC spec).
   414→fn zvofe_parse_burc(path: &Path) -> Result<vofe_BurcEnv, String> {
   415→    if !path.exists() {
   416→        return Err(format!("burc.env not found: {}", path.display()));
   417→    }
   418→
   419→    // Get the parent directory of burc.env for path resolution
   420→    let burc_parent = path
   421→        .parent()
   422→        .ok_or_else(|| "burc.env path has no parent directory".to_string())?;
   423→
   424→    let content = fs::read_to_string(path)
   425→        .map_err(|e| format!("Failed to read burc.env: {}", e))?;
   426→
   427→    let mut vars: HashMap<String, String> = HashMap::new();
   428→
   429→    for line in content.lines() {
   430→        let line = line.trim();
   431→
   432→        // Skip comments and empty lines
   433→        if line.is_empty() || line.starts_with('#') {
   434→            continue;
   435→        }
   436→
   437→        // Parse KEY=VALUE (handle quoted values)
   438→        if let Some(eq_pos) = line.find('=') {
   439→            let key = line[..eq_pos].trim();
   440→            let mut value = line[eq_pos + 1..].trim();
   441→
   442→            // Remove surrounding quotes if present
   443→            if (value.starts_with('"') && value.ends_with('"'))
   444→                || (value.starts_with('\'') && value.ends_with('\''))
   445→            {
   446→                value = &value[1..value.len() - 1];
   447→            }
   448→
   449→            vars.insert(key.to_string(), value.to_string());
   450→        }
   451→    }
   452→
   453→    let tools_dir_str = vars
   454→        .get("BURC_TOOLS_DIR")
   455→        .ok_or_else(|| "burc.env missing required variable: BURC_TOOLS_DIR".to_string())?;
   456→
   457→    let project_root_str = vars
   458→        .get("BURC_PROJECT_ROOT")
   459→        .ok_or_else(|| "burc.env missing required variable: BURC_PROJECT_ROOT".to_string())?;
   460→
   461→    // BURC_PROJECT_ROOT is the path from burc.env's location to project root
   462→    let project_root = burc_parent.join(project_root_str);
   463→    let project_root = project_root
   464→        .canonicalize()
   465→        .map_err(|e| format!("BURC_PROJECT_ROOT path invalid ({}): {}", project_root.display(), e))?;
   466→
   467→    // Resolve tools_dir relative to project_root (per BURC spec)
   468→    let tools_dir = project_root.join(tools_dir_str);
   469→    let tools_dir = tools_dir
   470→        .canonicalize()
   471→        .map_err(|e| format!("BURC_TOOLS_DIR path invalid ({}): {}", tools_dir.display(), e))?;
   472→
   473→    // Parse BURC_MANAGED_KITS (comma-separated list)
   474→    let managed_kits_str = vars
   475→        .get("BURC_MANAGED_KITS")
   476→        .ok_or_else(|| "burc.env missing required variable: BURC_MANAGED_KITS".to_string())?;
   477→
   478→    let managed_kits: Vec<String> = managed_kits_str
   479→        .split(',')
   480→        .map(|s| s.trim().to_string())
   481→        .filter(|s| !s.is_empty())
   482→        .collect();
   483→
   484→    if managed_kits.is_empty() {
   485→        return Err("BURC_MANAGED_KITS must specify at least one kit".to_string());
   486→    }
   487→
   488→    Ok(vofe_BurcEnv {
   489→        tools_dir,
   490→        project_root,
   491→        managed_kits,
   492→    })
   493→}
   494→
   495→/// Read brand file and extract hallmark and kit list.
   496→fn zvofe_read_brand(path: &Path) -> Result<(u32, Vec<String>), String> {
   497→    if !path.exists() {
   498→        return Err(format!("Brand file not found: {}", path.display()));
   499→    }
   500→
   501→    let content = fs::read_to_string(path)
   502→        .map_err(|e| format!("Failed to read brand file: {}", e))?;
   503→
   504→    let json: serde_json::Value = serde_json::from_str(&content)
   505→        .map_err(|e| format!("Failed to parse brand JSON: {}", e))?;
   506→
   507→    let hallmark = json
   508→        .get(VOFE_BRAND_HALLMARK)
   509→        .and_then(|v| v.as_u64())
   510→        .map(|v| v as u32)
   511→        .ok_or_else(|| "Brand file missing hallmark".to_string())?;
   512→
   513→    let kits = json
   514→        .get(VOFE_BRAND_KITS)
   515→        .and_then(|v| v.as_array())
   516→        .ok_or_else(|| "Brand file missing kits array".to_string())?;
   517→
   518→    let kit_ids: Vec<String> = kits
   519→        .iter()
   520→        .filter_map(|v| v.as_str().map(String::from))
   521→        .collect();
   522→
   523→    if kit_ids.is_empty() {
   524→        return Err("Brand file has empty kits array".to_string());
   525→    }
   526→
   527→    Ok((hallmark, kit_ids))
   528→}
   529→
   530→/// Copy a kit directory and route special files.
   531→/// Returns (files_copied, commands_routed, hooks_routed).
   532→fn zvofe_copy_kit(
   533→    source: &Path,
   534→    dest: &Path,
   535→    project_root: &Path,
   536→    kit_id: &str,
   537→) -> Result<(u32, u32, u32), String> {
   538→    let mut files = 0u32;
   539→    let mut commands = 0u32;
   540→    let mut hooks = 0u32;
   541→
   542→    // Get cipher from kit_id (e.g., "jjk" -> "jj")
   543→    let cipher = &kit_id[..kit_id.len().saturating_sub(1)];
   544→
   545→    // Walk source directory
   546→    let entries = zvofe_walk_dir(source)?;
   547→
   548→    for entry in entries {
   549→        let rel_path = entry
   550→            .strip_prefix(source)
   551→            .map_err(|e| format!("Path strip failed: {}", e))?;
   552→
   553→        let file_name = rel_path
   554→            .file_name()
   555→            .and_then(|n| n.to_str())
   556→            .unwrap_or("");
   557→
   558→        // Determine destination based on file type
   559→        let dest_path = if zvofe_is_command_file(file_name, cipher) {
   560→            // Route commands to .claude/commands/
   561→            let commands_dir = project_root.join(".claude").join("commands");
   562→            fs::create_dir_all(&commands_dir)
   563→                .map_err(|e| format!("Failed to create commands dir: {}", e))?;
   564→            commands += 1;
   565→            commands_dir.join(file_name)
   566→        } else if zvofe_is_hook_file(file_name, cipher) {
   567→            // Route hooks to .claude/hooks/
   568→            let hooks_dir = project_root.join(".claude").join("hooks");
   569→            fs::create_dir_all(&hooks_dir)
   570→                .map_err(|e| format!("Failed to create hooks dir: {}", e))?;
   571→            hooks += 1;
   572→            hooks_dir.join(file_name)
   573→        } else {
   574→            // Default: preserve relative path in kit directory
   575→            dest.join(rel_path)
   576→        };
   577→
   578→        // Create parent directories
   579→        if let Some(parent) = dest_path.parent() {
   580→            fs::create_dir_all(parent)
   581→                .map_err(|e| format!("Failed to create dir {}: {}", parent.display(), e))?;
   582→        }
   583→
   584→        // Copy file
   585→        fs::copy(&entry, &dest_path)
   586→            .map_err(|e| format!("Failed to copy {} to {}: {}", entry.display(), dest_path.display(), e))?;
   587→
   588→        files += 1;
   589→    }
   590→
   591→    Ok((files, commands, hooks))
   592→}
   593→
   594→/// Walk directory recursively, returning all file paths.
   595→fn zvofe_walk_dir(dir: &Path) -> Result<Vec<PathBuf>, String> {
   596→    let mut files = Vec::new();
   597→
   598→    if !dir.is_dir() {
   599→        return Ok(files);
   600→    }
   601→
   602→    let entries = fs::read_dir(dir)
   603→        .map_err(|e| format!("Failed to read dir {}: {}", dir.display(), e))?;
   604→
   605→    for entry in entries {
   606→        let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
   607→        let path = entry.path();
   608→
   609→        if path.is_dir() {
   610→            files.extend(zvofe_walk_dir(&path)?);
   611→        } else {
   612→            files.push(path);
   613→        }
   614→    }
   615→
   616→    Ok(files)
   617→}
   618→
   619→/// Check if file is a command file (matches {cipher}c-*.md pattern).
   620→fn zvofe_is_command_file(file_name: &str, cipher: &str) -> bool {
   621→    let prefix = format!("{}c-", cipher);
   622→    file_name.starts_with(&prefix) && file_name.ends_with(".md")
   623→}
   624→
   625→/// Check if file is a hook file (matches {cipher}h_* pattern).
   626→fn zvofe_is_hook_file(file_name: &str, cipher: &str) -> bool {
   627→    let prefix = format!("{}h_", cipher);
   628→    file_name.starts_with(&prefix)
   629→}
