   631→/// Read managed section templates from parcel.
   632→fn zvofe_read_templates(
   633→    parcel_dir: &Path,
   634→    kit_ids: &[String],
   635→) -> Result<Vec<voff_ManagedSection>, String> {
   636→    let mut sections = Vec::new();
   637→
   638→    for kit_id in kit_ids {
   639→        let kit = vofc_find_kit_by_id(kit_id)
   640→            .ok_or_else(|| format!("Kit not in registry: {}", kit_id))?;
   641→
   642→        let templates_dir = parcel_dir.join("kits").join(kit_id).join("templates");
   643→
   644→        for section in kit.managed_sections {
   645→            let template_path = templates_dir.join(section.template_path);
   646→            if !template_path.exists() {
   647→                return Err(format!(
   648→                    "Template not found in parcel: {}",
   649→                    template_path.display()
   650→                ));
   651→            }
   652→
   653→            let content = fs::read_to_string(&template_path)
   654→                .map_err(|e| format!("Failed to read template {}: {}", section.template_path, e))?;
   655→
   656→            sections.push(voff_ManagedSection {
   657→                tag: section.tag.to_string(),
   658→                content,
   659→            });
   660→        }
   661→    }
   662→
   663→    Ok(sections)
   664→}
   665→
   666→/// Freshen CLAUDE.md with managed sections.
   667→fn zvofe_freshen_claude(
   668→    claude_path: &Path,
   669→    sections: &[voff_ManagedSection],
   670→) -> Result<(), String> {
   671→    // Read existing content or start with empty
   672→    let content = if claude_path.exists() {
   673→        fs::read_to_string(claude_path)
   674→            .map_err(|e| format!("Failed to read CLAUDE.md: {}", e))?
   675→    } else {
   676→        "# Claude Code Project Memory\n".to_string()
   677→    };
   678→
   679→    // Freshen with new sections
   680→    let result = voff_freshen(&content, sections);
   681→
   682→    // Write back
   683→    fs::write(claude_path, &result.content)
   684→        .map_err(|e| format!("Failed to write CLAUDE.md: {}", e))?;
   685→
   686→    Ok(())
   687→}
   688→
   689→/// Collapse CLAUDE.md managed sections to UNINSTALLED markers.
   690→fn zvofe_collapse_claude(claude_path: &Path, tags: &[String]) -> Result<(), String> {
   691→    if !claude_path.exists() {
   692→        return Ok(()); // Nothing to collapse
   693→    }
   694→
   695→    let content = fs::read_to_string(claude_path)
   696→        .map_err(|e| format!("Failed to read CLAUDE.md: {}", e))?;
   697→
   698→    let tag_refs: Vec<&str> = tags.iter().map(|s| s.as_str()).collect();
   699→    let collapsed = voff_collapse(&content, &tag_refs);
   700→
   701→    fs::write(claude_path, &collapsed)
   702→        .map_err(|e| format!("Failed to write CLAUDE.md: {}", e))?;
   703→
   704→    Ok(())
   705→}
   706→
   707→/// Remove files matching a pattern from a directory.
   708→/// If is_command is true, matches {cipher}c-*.md; otherwise matches {cipher}h_*
   709→/// Returns count of files removed.
   710→fn zvofe_remove_matching_files(dir: &Path, cipher: &str, is_command: bool) -> Result<u32, String> {
   711→    let mut count = 0u32;
   712→
   713→    let entries = fs::read_dir(dir)
   714→        .map_err(|e| format!("Failed to read directory {}: {}", dir.display(), e))?;
   715→
   716→    for entry in entries {
   717→        let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
   718→        let path = entry.path();
   719→
   720→        if !path.is_file() {
   721→            continue;
   722→        }
   723→
   724→        let file_name = path
   725→            .file_name()
   726→            .and_then(|n| n.to_str())
   727→            .unwrap_or("");
   728→
   729→        let matches = if is_command {
   730→            zvofe_is_command_file(file_name, cipher)
   731→        } else {
   732→            zvofe_is_hook_file(file_name, cipher)
   733→        };
   734→
   735→        if matches {
   736→            fs::remove_file(&path)
   737→                .map_err(|e| format!("Failed to remove {}: {}", path.display(), e))?;
   738→            count += 1;
   739→        }
   740→    }
   741→
   742→    Ok(count)
   743→}
   744→
   745→#[cfg(test)]
   746→mod tests {
   747→    use super::*;
   748→
   749→    #[test]
   750→    fn test_is_command_file() {
   751→        assert!(zvofe_is_command_file("jjc-heat-mount.md", "jj"));
   752→        assert!(zvofe_is_command_file("vvc-commit.md", "vv"));
   753→        assert!(!zvofe_is_command_file("jjw_workbench.sh", "jj"));
   754→        assert!(!zvofe_is_command_file("README.md", "jj"));
   755→    }
   756→
   757→    #[test]
   758→    fn test_is_hook_file() {
   759→        assert!(zvofe_is_hook_file("jjh_post_commit.sh", "jj"));
   760→        assert!(zvofe_is_hook_file("vvh_pre_push", "vv"));
   761→        assert!(!zvofe_is_hook_file("jjc-heat-mount.md", "jj"));
   762→        assert!(!zvofe_is_hook_file("jjw_workbench.sh", "jj"));
   763→    }
   764→
   765→    #[test]
   766→    fn test_parse_burc_simple() {
   767→        use std::io::Write;
   768→        let temp_dir = std::env::temp_dir().join("vofe_test_burc");
   769→        let _ = fs::remove_dir_all(&temp_dir);
   770→
   771→        // Create directory structure: temp/buk/burc.env, temp/project, temp/project/Tools
   772→        let buk_dir = temp_dir.join("buk");
   773→        let project_dir = temp_dir.join("project");
   774→        let tools_dir = project_dir.join("Tools");
   775→        fs::create_dir_all(&buk_dir).unwrap();
   776→        fs::create_dir_all(&tools_dir).unwrap();
   777→
   778→        let burc_path = buk_dir.join("burc.env");
   779→        let mut f = fs::File::create(&burc_path).unwrap();
   780→        writeln!(f, "# Comment").unwrap();
   781→        writeln!(f, "BURC_PROJECT_ROOT=../project").unwrap();
   782→        writeln!(f, "BURC_TOOLS_DIR=Tools").unwrap();
   783→        writeln!(f, "BURC_MANAGED_KITS=buk,jjk").unwrap();
   784→
   785→        let result = zvofe_parse_burc(&burc_path).unwrap();
   786→        assert_eq!(result.project_root.canonicalize().unwrap(), project_dir.canonicalize().unwrap());
   787→        assert_eq!(result.tools_dir.canonicalize().unwrap(), tools_dir.canonicalize().unwrap());
   788→        assert_eq!(result.managed_kits, vec!["buk", "jjk"]);
   789→
   790→        let _ = fs::remove_dir_all(&temp_dir);
   791→    }
   792→
   793→    #[test]
   794→    fn test_parse_burc_quoted() {
   795→        use std::io::Write;
   796→        let temp_dir = std::env::temp_dir().join("vofe_test_burc_quoted");
   797→        let _ = fs::remove_dir_all(&temp_dir);
   798→
   799→        // Create directory structure
   800→        let buk_dir = temp_dir.join("buk");
   801→        let project_dir = temp_dir.join("project");
   802→        let tools_dir = project_dir.join("Tools");
   803→        fs::create_dir_all(&buk_dir).unwrap();
   804→        fs::create_dir_all(&tools_dir).unwrap();
   805→
   806→        let burc_path = buk_dir.join("burc.env");
   807→        let mut f = fs::File::create(&burc_path).unwrap();
   808→        writeln!(f, "BURC_PROJECT_ROOT=\"../project\"").unwrap();
   809→        writeln!(f, "BURC_TOOLS_DIR='Tools'").unwrap();
   810→        writeln!(f, "BURC_MANAGED_KITS=\"vvk\"").unwrap();
   811→
   812→        let result = zvofe_parse_burc(&burc_path).unwrap();
   813→        assert_eq!(result.project_root.canonicalize().unwrap(), project_dir.canonicalize().unwrap());
   814→        assert_eq!(result.tools_dir.canonicalize().unwrap(), tools_dir.canonicalize().unwrap());
   815→        assert_eq!(result.managed_kits, vec!["vvk"]);
